27	pub fn is_builtin_excluded(path: &Path) -> bool {
28	    path.components().any(|c| {
29	        if let Component::Normal(name) = c {
30	            BUILTIN_EXCLUDED_DIRS.contains(&name.to_str().unwrap_or(""))
31	        } else {
32	            false
33	        }
34	    })
35	}
