37	pub fn build_glob_set(patterns: &[String]) -> Result<GlobSet, globset::Error> {
38	    let mut builder = GlobSetBuilder::new();
39	    for pat in patterns {
40	        builder.add(Glob::new(pat)?);
41	    }
42	    builder.build()
43	}
