45	const EXT_LANG_MAP: &[(&str, Lang)] = &[
46	    ("rs", Lang::Rust),
47	    ("js", Lang::JavaScript),
48	    ("jsx", Lang::JavaScript),
49	    ("ts", Lang::TypeScript),
50	    ("tsx", Lang::Tsx),
51	    ("py", Lang::Python),
52	];
53	
54	pub fn detect_lang(path: &Path) -> Option<Lang> {
55	    let ext = path.extension().and_then(|e| e.to_str())?;
56	    EXT_LANG_MAP
57	        .iter()
58	        .find(|(e, _)| *e == ext)
59	        .map(|(_, l)| *l)
60	}
61	
62	pub fn is_rust_file(path: &Path) -> bool {
63	    path.extension().and_then(|e| e.to_str()) == Some("rs")
64	}
65	
66	pub fn is_supported_file(path: &Path) -> bool {
67	    detect_lang(path).is_some()
68	}
69	
70	pub fn should_skip(path: &Path, exclude_set: &GlobSet) -> bool {
71	    if exclude_set.is_empty() {
72	        return false;
73	    }
74	    exclude_set.is_match(path)
75	}
