77	/// Returns whether a file should be scanned.
78	/// When force_lang is Some, every non-excluded, non-builtin-excluded file is scanned.
79	/// When force_lang is None, only files with recognized extensions are scanned.
80	pub fn should_scan_file(path: &Path, exclude_set: &GlobSet, force_lang: Option<Lang>) -> bool {
81	    if is_builtin_excluded(path) || should_skip(path, exclude_set) {
82	        return false;
83	    }
84	    match force_lang {
85	        Some(_) => true,
86	        None => is_supported_file(path),
87	    }
88	}
