90	pub fn collect_all_functions(
91	    paths: &[String],
92	    exclude_set: &GlobSet,
93	    force_lang: Option<Lang>,
94	) -> (Vec<FunctionInfo>, Vec<String>) {
95	    let mut functions: Vec<FunctionInfo> = Vec::new();
96	    let mut errors: Vec<String> = Vec::new();
97	    for path_str in paths {
98	        let path = Path::new(path_str);
99	        if !path.exists() {
100	            errors.push(format!("path does not exist: {}", path_str));
101	        } else {
102	            collect_functions_from_path(path, exclude_set, force_lang, &mut functions, &mut errors);
103	        }
104	    }
105	    (functions, errors)
106	}
107	
108	pub fn collect_functions_from_path(
109	    path: &Path,
110	    exclude_set: &GlobSet,
111	    force_lang: Option<Lang>,
112	    functions: &mut Vec<FunctionInfo>,
113	    errors: &mut Vec<String>,
114	) {
115	    if path.is_file() {
116	        collect_from_single_file(path, exclude_set, force_lang, functions, errors);
117	    } else {
118	        collect_from_directory(path, exclude_set, force_lang, functions, errors);
119	    }
120	}
121	
122	pub fn collect_from_single_file(
123	    path: &Path,
124	    exclude_set: &GlobSet,
125	    force_lang: Option<Lang>,
126	    functions: &mut Vec<FunctionInfo>,
127	    errors: &mut Vec<String>,
128	) {
129	    if should_scan_file(path, exclude_set, force_lang) {
130	        let lang = force_lang.or_else(|| detect_lang(path)).unwrap();
131	        process_file(path, lang, functions, errors);
132	    }
133	}
134	
135	fn process_walk_entry(
136	    entry: Result<ignore::DirEntry, ignore::Error>,
137	    exclude_set: &GlobSet,
138	    force_lang: Option<Lang>,
139	    functions: &mut Vec<FunctionInfo>,
140	    errors: &mut Vec<String>,
141	) {
142	    match entry {
143	        Ok(e) if e.file_type().map(|ft| ft.is_file()).unwrap_or(false) => {
144	            if should_scan_file(e.path(), exclude_set, force_lang) {
145	                let lang = force_lang.or_else(|| detect_lang(e.path())).unwrap();
146	                process_file(e.path(), lang, functions, errors);
147	            }
148	        }
149	        Ok(_) => {}
150	        Err(err) => errors.push(format!("walk error: {}", err)),
151	    }
152	}
153	
154	pub fn collect_from_directory(
155	    path: &Path,
156	    exclude_set: &GlobSet,
157	    force_lang: Option<Lang>,
158	    functions: &mut Vec<FunctionInfo>,
159	    errors: &mut Vec<String>,
160	) {
161	    let walker = WalkBuilder::new(path)
162	        .filter_entry(|e| {
163	            e.file_type().map(|ft| !ft.is_dir()).unwrap_or(true) || !is_builtin_excluded(e.path())
164	        })
165	        .build();
166	    for entry in walker {
167	        process_walk_entry(entry, exclude_set, force_lang, functions, errors);
168	    }
169	}
170	
171	pub fn process_file(
172	    path: &Path,
173	    lang: Lang,
174	    functions: &mut Vec<FunctionInfo>,
175	    errors: &mut Vec<String>,
176	) {
177	    let source = match std::fs::read_to_string(path) {
178	        Ok(s) => s,
179	        Err(e) => {
180	            errors.push(format!("cannot read {}: {}", path.display(), e));
181	            return;
182	        }
183	    };
184	
185	    let config: &LangConfig = lang_config(lang);
186	    match parse_source_tree_for(&source, lang) {
187	        Ok(tree) => {
188	            let file_str = path.to_string_lossy().to_string();
189	            extract_functions_with_config(tree.root_node(), &source, &file_str, config, functions);
190	        }
191	        Err(msg) => {
192	            errors.push(format!("{} in {}", msg, path.display()));
193	        }
194	    }
195	}
