90	pub fn jaccard(a: &[u64], b: &[u64]) -> f64 {
91	    if a.is_empty() && b.is_empty() {
92	        return 1.0;
93	    }
94	    let set_a: HashSet<u64> = a.iter().copied().collect();
95	    let set_b: HashSet<u64> = b.iter().copied().collect();
96	    let intersection = set_a.intersection(&set_b).count();
97	    let union = set_a.union(&set_b).count();
98	    if union == 0 {
99	        return 0.0;
100	    }
101	    intersection as f64 / union as f64
102	}
