108	pub fn make_pair(a: &FunctionInfo, b: &FunctionInfo, score: f64) -> DuplicatePair {
109	    let (left, right) = order_endpoints(a, b);
110	    DuplicatePair {
111	        score,
112	        left: PairEndpoint {
113	            file: left.file.clone(),
114	            start_line: left.start_line,
115	            end_line: left.end_line,
116	            nodes: left.node_hashes.len(),
117	        },
118	        right: PairEndpoint {
119	            file: right.file.clone(),
120	            start_line: right.start_line,
121	            end_line: right.end_line,
122	            nodes: right.node_hashes.len(),
123	        },
124	    }
125	}
