171	fn order_endpoints<'a>(
172	    a: &'a FunctionInfo,
173	    b: &'a FunctionInfo,
174	) -> (&'a FunctionInfo, &'a FunctionInfo) {
175	    let cmp = a
176	        .file
177	        .cmp(&b.file)
178	        .then_with(|| a.start_line.cmp(&b.start_line));
179	    if cmp == std::cmp::Ordering::Greater {
180	        (b, a)
181	    } else {
182	        (a, b)
183	    }
184	}
