190	        out.push_str(&format!(
191	            "  {}:{}-{}\n",
192	            p.left.file, p.left.start_line, p.left.end_line
193	        ));
194	        out.push_str(&format!(
195	            "  {}:{}-{}  ({} nodes / {} nodes)\n",
196	            p.right.file, p.right.start_line, p.right.end_line, p.left.nodes, p.right.nodes
197	        ));
198	    }
199	    out
200	}
