395	    let start = node.start_byte();
396	    let end = node.end_byte();
397	    source[start..end].to_string()
398	}
399	
400	pub fn build_normalized_subtree(
401	    node: tree_sitter::Node,
402	    source: &str,
403	    config: &LangConfig,
404	) -> String {
405	    if node.child_count() == 0 {
406	        return normalize_node_text(node, source, config);
407	    }
408	    let mut parts = vec![format!("({}:", node.kind())];
409	    let mut cursor = node.walk();
410	    for child in node.children(&mut cursor) {
411	        parts.push(build_normalized_subtree(child, source, config));
412	    }
413	    parts.push(")".to_string());
414	    parts.join("")
415	}
416	
417	fn hash_str(s: &str) -> u64 {
418	    use std::hash::{Hash, Hasher};
419	    let mut h = std::collections::hash_map::DefaultHasher::new();
420	    s.hash(&mut h);
421	    h.finish()
422	}
423	
424	fn collect_subtree_hashes(node: tree_sitter::Node, source: &str, config: &LangConfig) -> Vec<u64> {
425	    let mut hashes = Vec::new();
426	    collect_hashes_recursive(node, source, config, &mut hashes);
427	    hashes.sort_unstable();
428	    hashes
429	}
430	
431	fn collect_hashes_recursive(
432	    node: tree_sitter::Node,
433	    source: &str,
434	    config: &LangConfig,
435	    hashes: &mut Vec<u64>,
436	) {
437	    let subtree = build_normalized_subtree(node, source, config);
438	    hashes.push(hash_str(&subtree));
439	    let mut cursor = node.walk();
440	    for child in node.children(&mut cursor) {
441	        collect_hashes_recursive(child, source, config, hashes);
442	    }
443	}
